import './Main.scss';

export const Main = () => (
  <div className="Main">
    Sw
    <Route path="/home">
      <HomePage />
    </Route>
    <Route path="/articles">
      <ArticlesPage />
    </Route>
    <Redirect path="/" to="/home" />
  </div>
);
